import React, { useState, useEffect } from 'react';
import { Container, Row, Col, Card, Form, Button, Alert, Spinner } from 'react-bootstrap';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const [formData, setFormData] = useState({
        email: '',
        password: ''
    });
    const [showPassword, setShowPassword] = useState(false);
    const { login, isAuthenticated, isLoading, error, clearError } = useAuth();
    const navigate = useNavigate();

    // Redirigir si ya está autenticado
    useEffect(() => {
        if (isAuthenticated) {
            navigate('/dashboard');
        }
    }, [isAuthenticated, navigate]);

    // Limpiar errores cuando el componente se monta
    useEffect(() => {
        clearError();
    }, [clearError]);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: value
        }));
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        
        if (!formData.email || !formData.password) {
            return;
        }

        try {
            const result = await login(formData.email, formData.password);
            
            if (result.success) {
                // Pequeño delay para asegurar que el estado se actualice
                setTimeout(() => {
                    navigate('/dashboard');
                }, 100);
            }
        } catch (error) {
            console.error('Login error:', error);
        }
    };

    // Usuarios de ejemplo para pruebas
    const usuariosEjemplo = [
        { email: 'admin@sirer.com', password: 'admin123', rol: 'Administrador' },
        { email: 'mozo@sirer.com', password: 'mozo123', rol: 'Mozo' },
        { email: 'cocina@sirer.com', password: 'cocina123', rol: 'Cocina' },
        { email: 'cajero@sirer.com', password: 'cajero123', rol: 'Cajero' }
    ];

    const llenarCredenciales = (email, password) => {
        setFormData({ email, password });
    };

    return (
        <div className="min-vh-100 d-flex align-items-center" style={{
            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'
        }}>
            <Container>
                <Row className="justify-content-center">
                    <Col md={8} lg={6} xl={5}>
                        <Card className="shadow-lg border-0">
                            <Card.Body className="p-5">
                                {/* Header */}
                                <div className="text-center mb-4">
                                    <h1 className="h3 mb-3 fw-bold text-primary">
                                        🍽️ SIRER
                                    </h1>
                                    <p className="text-muted">
                                        Sistema Integral para Restaurantes
                                    </p>
                                </div>

                                {/* Error Alert */}
                                {error && (
                                    <Alert variant="danger" className="mb-4">
                                        <i className="fas fa-exclamation-triangle me-2"></i>
                                        {error}
                                    </Alert>
                                )}

                                {/* Formulario de Login */}
                                <Form onSubmit={handleSubmit}>
                                    <Form.Group className="mb-3">
                                        <Form.Label>
                                            <i className="fas fa-envelope me-2"></i>
                                            Email
                                        </Form.Label>
                                        <Form.Control
                                            type="email"
                                            name="email"
                                            value={formData.email}
                                            onChange={handleChange}
                                            placeholder="Ingresa tu email"
                                            required
                                            disabled={isLoading}
                                        />
                                    </Form.Group>

                                    <Form.Group className="mb-4">
                                        <Form.Label>
                                            <i className="fas fa-lock me-2"></i>
                                            Contraseña
                                        </Form.Label>
                                        <div className="position-relative">
                                            <Form.Control
                                                type={showPassword ? 'text' : 'password'}
                                                name="password"
                                                value={formData.password}
                                                onChange={handleChange}
                                                placeholder="Ingresa tu contraseña"
                                                required
                                                disabled={isLoading}
                                            />
                                            <Button
                                                variant="link"
                                                className="position-absolute top-50 end-0 translate-middle-y pe-3 text-muted"
                                                onClick={() => setShowPassword(!showPassword)}
                                                style={{ border: 'none', background: 'none' }}
                                            >
                                                <i className={`fas ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
                                            </Button>
                                        </div>
                                    </Form.Group>

                                    <Button
                                        type="submit"
                                        variant="primary"
                                        size="lg"
                                        className="w-100 mb-3"
                                        disabled={isLoading || !formData.email || !formData.password}
                                    >
                                        {isLoading ? (
                                            <>
                                                <Spinner animation="border" size="sm" className="me-2" />
                                                Iniciando sesión...
                                            </>
                                        ) : (
                                            <>
                                                <i className="fas fa-sign-in-alt me-2"></i>
                                                Iniciar Sesión
                                            </>
                                        )}
                                    </Button>
                                </Form>

                                {/* Usuarios de ejemplo */}
                                <div className="mt-4">
                                    <hr />
                                    <p className="text-center text-muted mb-3">
                                        <small>Usuarios de prueba:</small>
                                    </p>
                                    <Row className="g-2">
                                        {usuariosEjemplo.map((usuario, index) => (
                                            <Col xs={6} key={index}>
                                                <Button
                                                    variant="outline-secondary"
                                                    size="sm"
                                                    className="w-100"
                                                    onClick={() => llenarCredenciales(usuario.email, usuario.password)}
                                                    disabled={isLoading}
                                                >
                                                    {usuario.rol}
                                                </Button>
                                            </Col>
                                        ))}
                                    </Row>
                                </div>

                                {/* Footer */}
                                <div className="text-center mt-4">
                                    <small className="text-muted">
                                        © 2025 SIRER - Sistema de Gestión de Restaurantes
                                    </small>
                                </div>
                            </Card.Body>
                        </Card>
                    </Col>
                </Row>
            </Container>
        </div>
    );
};

export default Login;
